// ============================================================================
// miles-slack-event-router · Classify Event
// ----------------------------------------------------------------------------
// Resuelve los 3 ejes de clasificacion y devuelve una unica `action`.
//   Eje 1 (que):    tipo de evento Slack
//   Eje 2 (quien):  origen del evento (Claude firmado / Miles / bot / humano)
//   Eje 3 (donde):  canal REQ vs otro · raiz vs reply · con/sin mencion
//
// Acciones posibles: 'app_home' | 'capture_req' | 'ignore'
//
// Campos efimeros propagados en la rama app_home_opened (sin persistencia):
//   - taking : EWI en transicion optimista (boton 'Tomando...')
//   - tab    : pseudo-tab activo de las vistas tecnicas ('refinamiento'|'desarrollo')
//              Vacio -> el builder usa su default (refinamiento).
//   Ambos viajan en el evento sintetico que postea el actions-router al refrescar.
// ============================================================================

const body  = $json.body || {};
const event = body.event || {};

const MILES_ID  = 'U0ANEJ5BRPZ';
const CLAUDE_ID = 'U0AHZHTQE22';
const REQ_CHANNELS = ['C0AJ2599DA6','C0AJ67HK0ES','C0AK2PW5BGQ','C0AKNPCNNSU','C0AJMRFP0TD','C0ARDGP8134'];
const CLAUDE_SIGNATURES = ['Sent using','Sent with','Sent via','Sent from','Sent by',
  'Enviado usando','Enviado mediante','Enviado con','Enviado vía','Enviado via','Enviado por','Enviado desde'];

// 🧪 TESTING — Impersonar a otro usuario en App Home. null en produccion.
const IMPERSONATE = null;
// const IMPERSONATE = 'U0AUX6RT2G0';

const text = event.text || '';
const ignore = (reason) => [{ json: { action: 'ignore', _reason: reason } }];

const eventType = event.type || '';
const subtype   = event.subtype || '';
const isEditDelete = subtype === 'message_changed' || subtype === 'message_deleted' || !!event.edited;

if (isEditDelete) return ignore('edit_or_delete');

if (eventType === 'app_home_opened') {
  if (!event.user || event.user === MILES_ID) return ignore('home_non_human');
  return [{ json: {
    action: 'app_home',
    user_id: IMPERSONATE || event.user,
    publish_user_id: event.publish_as || event.user,
    taking: event.taking || '',
    tab: event.tab || ''
  } }];
}

if (event.user === MILES_ID || event.bot_id) {
  const sigOK = CLAUDE_SIGNATURES.some(s => text.includes(s)) && text.includes(CLAUDE_ID);
  if (!sigOK) return ignore('bot_or_miles');
}

const isClaudeSigned = CLAUDE_SIGNATURES.some(s => text.includes(s)) && text.includes(CLAUDE_ID);

const channel     = event.channel || '';
const isReqChannel = REQ_CHANNELS.includes(channel);
const isDM        = event.channel_type === 'im';
const isRoot      = !event.thread_ts || event.thread_ts === event.ts;

if (isDM) return ignore('dm_inbound');

if (eventType === 'message' && isClaudeSigned) {
  return ignore('claude_signed_message_dedup');
}

if (eventType === 'app_mention' && isClaudeSigned && isReqChannel && isRoot) {
  return [{ json: {
    action: 'capture_req',
    thread_ts: event.ts,
    channel_id: channel,
    user_id: event.user,
    message_text: text.replace(/<@[A-Z0-9]+>/g, '').trim(),
    source: 'claude'
  }}];
}

if (eventType === 'app_mention' && !isReqChannel) return ignore('mention_outside_req');
if (eventType === 'app_mention') return ignore('mention_unsigned_noop');
return ignore('no_match');

// ============================================================================
// miles-slack-event-router · Resolve Profile  (v4 — TL como perfil propio)
// ----------------------------------------------------------------------------
// Orden de precedencia (ver miles-home-discovery.md):
//   0. Group External -> 'externo' (vista mínima: solo Prioridades globales)
//   1. Group Head/C-Level + Area Technology -> 'it_lead' (vista global de IT)
//   2. Group Head/C-Level + Area Product    -> 'producto' (vista de PM)
//   3. Group Head / C-Level (otras areas)   -> 'lider'
//   4. Business Area = Technology + Role "Technical Lead" -> 'tech_lead' (NUEVO)
//   5. Business Area = Technology (resto)    -> 'tecnico' (dev comun)
//   6. Business Area = Product    -> 'producto'
//   7. Group Analyst            -> 'stakeholder'
//   8. Group Manager/Specialist -> 'stakeholder' (de su area)
//   9. fallback                 -> 'producto'
//
// El TL ya NO se modela con flag is_tech_lead dentro de 'tecnico': es su propio
// perfil 'tech_lead' con builder y salida de Switch propios. Se mantiene
// is_tech_lead en el output por compatibilidad (true solo para tech_lead).
// ============================================================================

const stkRes = $('Query Stakeholder by Slack ID').first().json.results || [];
const slackUser = $('Classify Event').first().json.user_id;
const publishUser = $('Classify Event').first().json.publish_user_id || slackUser;
const info = $('Get Home User Info').first().json;
const sProfile = (info.user && info.user.profile) || {};
const firstName = sProfile.first_name || sProfile.display_name || sProfile.real_name || 'che';

const capRes = $('Query Capability — ticket.take').first().json.results || [];
const ticketTakeId = capRes[0] ? capRes[0].id : null;

function emit(profile, reason, extra={}) {
  return [{ json: {
    profile, _reason: reason, user_id: slackUser, publish_user_id: publishUser, first_name: firstName,
    is_tech_lead: false, jira_id: null, business_area_id: null, ...extra
  } }];
}

if (stkRes.length === 0) return emit('producto', 'no_stakeholder_match', { group: [], capabilities: [], role: '' });

const props = stkRes[0].properties || {};
const group = (props['Group']?.multi_select || []).map(g => g.name);
const capabilities = (props['Capabilities']?.relation || []).map(r => r.id);
const businessAreaId = (props['Business Area']?.relation || [])[0]?.id || null;
const role = props['Role']?.rich_text?.[0]?.plain_text || '';
const jiraId = props['Jira ID']?.rich_text?.[0]?.plain_text || null;

const base = { group, capabilities, role, jira_id: jiraId, business_area_id: businessAreaId };

const AREA_TECHNOLOGY = '376e8880-def6-8188-9ddc-e3e24b20ee64';
const AREA_PRODUCT    = '376e8880-def6-813a-a216-e704c2b59c8b';

// 0) Externo -> vista mínima (solo Prioridades globales, Nivel 4).
// Precede a TODO: un externo es externo aunque tenga un Business Area asignada.
// Evita que caiga en el fallback 'producto' (era el bug: Externos veían la vista de PM).
if (group.includes('External')) return emit('externo', 'group_external', base);

// 1) Liderazgo de IT
if ((group.includes('C-Level') || group.includes('Head')) && businessAreaId === AREA_TECHNOLOGY) {
  return emit('it_lead', 'group_head_tech', base);
}
// 2) Liderazgo de Producto
if ((group.includes('C-Level') || group.includes('Head')) && businessAreaId === AREA_PRODUCT) {
  return emit('producto', 'group_head_product', base);
}
// 3) Head / C-Level (otras areas)
if (group.includes('C-Level') || group.includes('Head')) return emit('lider', 'group_head', base);

// 4) Area Technology + Role Technical Lead -> tech_lead (perfil propio)
if (businessAreaId === AREA_TECHNOLOGY && /technical lead/i.test(role)) {
  return emit('tech_lead', 'tech_lead', { ...base, is_tech_lead: true });
}
// 5) Area Technology (resto) -> tecnico (dev comun)
if (businessAreaId === AREA_TECHNOLOGY) {
  return emit('tecnico', 'dev', base);
}
// 6) Area Product -> producto
if (businessAreaId === AREA_PRODUCT) return emit('producto', 'area_product', base);

// 7) Analyst -> stakeholder
if (group.includes('Analyst')) return emit('stakeholder', 'group_analyst', base);

// 8) Manager / Specialist (no tech, no product) -> stakeholder
if (group.includes('Manager') || group.includes('Specialist')) {
  return emit('stakeholder', 'manager_non_tech', base);
}

// 9) fallback
return emit('producto', 'fallback', base);

// Identidad + datos Jira ya resueltos aguas arriba
const bj = $('Build JQL').first().json;
const userId = bj.user_id;
const publishUserId = bj.publish_user_id || bj.user_id;
const firstName = bj.first_name || 'che';
const myJiraId = bj.jira_id || null;
// La respuesta del handler puede venir como objeto o string JSON
let _resp = $('Query Jira (via handler)').item.json;
if (typeof _resp === 'string') { try { _resp = JSON.parse(_resp); } catch(e){ _resp = {}; } }
if (_resp && _resp.body && !_resp.issues) {
  let b = _resp.body;
  if (typeof b === 'string') { try { b = JSON.parse(b); } catch(e){ b = {}; } }
  _resp = b;
}
const issues = (_resp && _resp.issues) || [];
const prioCounts = {};
// byParent: child de los espejos Story de going-on (Fetch Children Progress).
let _children = $json;
if (typeof _children === 'string') { try { _children = JSON.parse(_children); } catch(e){ _children = {}; } }
if (_children && _children.body && !_children.byParent) {
  let b = _children.body; if (typeof b === 'string') { try { b = JSON.parse(b); } catch(e){ b = {}; } }
  _children = b;
}
const byParent = (_children && _children.byParent) || {};

function adfToText(node){
  if (!node || typeof node !== 'object') return '';
  const t = node.type;
  if (t === 'text') return node.text || '';
  if (t === 'hardBreak') return ' ';
  if (t === 'mention') return (node.attrs && node.attrs.text) || '';
  if (t === 'emoji')   return (node.attrs && (node.attrs.text || node.attrs.shortName)) || '';
  if (t === 'inlineCard' || t === 'blockCard') {
    const u = node.attrs && node.attrs.url ? node.attrs.url : '';
    return u ? `[${u}]` : '[link]';
  }
  const kids = Array.isArray(node.content) ? node.content : [];
  if (t === 'tableCell' || t === 'tableHeader') return kids.map(adfToText).filter(Boolean).join(' ').trim();
  if (t === 'tableRow') return kids.map(adfToText).filter(Boolean).join(' · ');
  if (t === 'table')    return kids.map(adfToText).filter(Boolean).join('\n');
  if (t === 'paragraph') return kids.map(adfToText).join('');
  return kids.map(adfToText).filter(Boolean).join('\n');
}
function blockedCauseText(adf){
  if (!adf) return null;
  let txt = adfToText(adf).replace(/\n{2,}/g, '\n').replace(/[ \t]{2,}/g, ' ').trim();
  if (!txt) return null;
  const LIMIT = 280;
  if (txt.length > LIMIT) txt = txt.slice(0, LIMIT - 1).trimEnd() + '…';
  return txt;
}
function daysAgo(iso){
  if (!iso) return null;
  const then = new Date(iso); if (isNaN(then)) return null;
  return Math.floor((Date.now() - then.getTime()) / 86400000);
}
function agoLabel(iso){
  const d = daysAgo(iso);
  if (d === null) return null;
  if (d <= 0) return 'hoy';
  if (d === 1) return 'hace 1 día';
  return `hace ${d} días`;
}
function prioEmoji(prioName){
  const p = (prioName || '').toLowerCase();
  if (p === 'highest') return '🔺';
  if (p === 'high')    return '🔴';
  if (p === 'medium')  return '🟠';
  if (p === 'low')     return '🟢';
  return '⚪';
}
function clip(s, n){ s = String(s||''); return s.length > n ? s.slice(0, n-1).trimEnd() + '…' : s; }

function espejoValido(issuelinks){
  if (!Array.isArray(issuelinks)) return null;
  for (const l of issuelinks) {
    const t = l.type || {};
    if (t.name === 'Problem/Incident' && t.outward === 'causes' && l.outwardIssue) {
      const k = l.outwardIssue.key || '';
      const ty = ((l.outwardIssue.fields || {}).issuetype || {}).name || '';
      if (k.startsWith('EWI-') && (ty === 'Epic' || ty === 'Story')) {
        const stObj = ((l.outwardIssue.fields || {}).status || {});
        const st = stObj.name || '';
        const stCat = (stObj.statusCategory || {}).key || '';
        return { key: k, type: ty, status: st, statusCategory: stCat };
      }
    }
  }
  return null;
}
function rankCmp(a, b){
  if (!a.rank && !b.rank) return 0;
  if (!a.rank) return 1;
  if (!b.rank) return -1;
  return a.rank < b.rank ? -1 : (a.rank > b.rank ? 1 : 0);
}
const PWI_PHASE_ORDER = { 'SENT TO DEV':0, 'READY FOR DEV':1, 'IN DEVELOPMENT':2, 'BLOCKED':3 };
function phaseCmp(a, b){
  const pa = PWI_PHASE_ORDER[a.status] ?? 99;
  const pb = PWI_PHASE_ORDER[b.status] ?? 99;
  if (pa !== pb) return pa - pb;
  return rankCmp(a, b);
}
function progressBar(pct){
  const filled = Math.round((pct/100)*10);
  return '\u2593'.repeat(filled) + '\u2591'.repeat(10-filled) + ` ${pct}%`;
}
function completitud(esp, byParent){
  if (!esp) return { pct: 0, label: '\u2014' };
  const childs = (byParent && byParent[esp.key]) || [];
  if (childs.length > 0) {
    const done = childs.filter(c => c.statusCategory === 'done').length;
    const total = childs.length;
    const pct = Math.round((done/total)*100);
    return { pct, label: `${done}/${total}` };
  }
  const espDone = (esp.statusCategory || '').toLowerCase() === 'done';
  return { pct: espDone ? 100 : 0, label: '\u2014' };
}
function buildPrioridadesGlobales(rows, opts){
  opts = opts || {};
  const tecnico = !!opts.tecnico;
  const counts = (opts.counts && typeof opts.counts === 'object') ? opts.counts : null;
  const byParent = (opts.byParent && typeof opts.byParent === 'object') ? opts.byParent : {};
  const reqs = rows.filter(r => r.issueType === 'Requirement');
  const next = [], going = [];
  for (const r of reqs) {
    const esp = espejoValido(r.issuelinks);
    r._esp = esp;
    if (!esp || esp.type === 'Epic') next.push(r);
    else going.push(r);
  }
  next.sort(rankCmp);
  going.sort(phaseCmp);
  if (counts) { counts.next = next.length; counts.going = going.length; }
  const blocks = [
    { type:'header', text:{ type:'plain_text', text:':round_pushpin: Prioridades globales', emoji:true } },
    { type:'context', elements:[{ type:'mrkdwn', text:'_Cola de Producto y Tecnología · priorización y seguimiento_' }] }
  ];
  if (next.length) {
    const headerNext = tecnico
      ? ['Rank','PWI','Requerimiento','Estado','Prioridad','Área','EWI']
      : ['Rank','PWI','Requerimiento','Estado','Prioridad','Área'];
    const rowsNext = next.map((r, i) => {
      const base = [String(i+1), r.key, r.summary, r.status, r.priority||'—', r.area||'—'];
      if (tecnico) base.push(r._esp ? r._esp.key : '—');
      return base;
    });
    blocks.push(table(`What's next? (${next.length})`, headerNext, rowsNext));
  } else {
    blocks.push(emptyNote(`*What's next? (0)* — _Sin requerimientos en cola de priorización._`));
  }
  if (going.length) {
    const headerGoing = tecnico
      ? ['PWI','Requerimiento','Estado','Avance','Prioridad','Área','EWI']
      : ['PWI','Requerimiento','Estado','Avance','Prioridad','Área'];
    const rowsGoing = going.map(r => {
      const estadoEwi = r._esp ? r._esp.status : (r.status || '—');
      const comp = completitud(r._esp, byParent);
      const avance = progressBar(comp.pct) + (comp.label !== '—' ? ` (${comp.label})` : '');
      const base = [r.key, r.summary, estadoEwi, avance, r.priority||'—', r.area||'—'];
      if (tecnico) base.push(r._esp ? r._esp.key : '—');
      return base;
    });
    blocks.push(table(`What's going on? (${going.length})`, headerGoing, rowsGoing));
  } else {
    blocks.push(emptyNote(`*What's going on? (0)* — _Nada en desarrollo ahora._`));
  }
  return blocks;
}

function row(it){
  const f = it.fields || {};
  const a = f.assignee || null;
  return {
    key: it.key,
    summary: f.summary || '',
    status: f.status ? f.status.name : '',
    assignee: a ? (a.displayName || '') : '',
    assigneeId: a ? (a.accountId || '') : '',
    area: f.customfield_10310 ? (f.customfield_10310.value || f.customfield_10310.name || '') : '',
    priority: f.priority ? f.priority.name : '',
    blockedCause: blockedCauseText(f.customfield_10306),
    blockedSince: f.statuscategorychangedate || null,
    issueType: f.issuetype ? f.issuetype.name : '',
    project: (it.fields && it.fields.project && it.fields.project.key) || (String(it.key||'').split('-')[0]),
    issuelinks: (it.fields && it.fields.issuelinks) || [],
    rank: f.customfield_10019 || ''
  };
}
const rows = issues.map(row);
function inStatus(r, arr){ return arr.includes(r.status); }
const isMine = (r) => myJiraId && r.assigneeId === myJiraId;

function table(caption, header, dataRows){
  const head = header.map(h => ({type:'raw_text', text:h}));
  const body = dataRows.map(cells => cells.map(c => ({type:'raw_text', text:String(c)})));
  return { type:'data_table', caption, rows:[head, ...body] };
}
function emptyNote(txt){ return { type:'context', elements:[{type:'mrkdwn', text:txt}] }; }

function pwiCard(r, opts){
  opts = opts || {};
  const useBlocked = !!opts.useBlockedCause;
  const ago = agoLabel(r.blockedSince);
  const subParts = [];
  if (r.priority) subParts.push(`${prioEmoji(r.priority)} ${r.priority}`);
  if (r.area)     subParts.push(`📍 ${r.area}`);
  if (ago)        subParts.push(`⏱ ${ago}`);
  let bodyText;
  if (useBlocked) {
    bodyText = r.blockedCause ? r.blockedCause : '_Sin motivo en Blocked cause_';
  } else {
    bodyText = r.summary || '_Sin descripción_';
  }
  return {
    type: 'card',
    block_id: `card-${r.key}`,
    slack_icon: { type: 'icon', name: 'rocket' },
    title:    { type: 'mrkdwn', text: `*${r.key}* · ${clip(r.summary, 80)}` },
    subtitle: { type: 'mrkdwn', text: subParts.join('  ·  ') || '—' },
    body:     { type: 'mrkdwn', text: (bodyText && bodyText.length > 200 ? bodyText.slice(0, 199).trimEnd() + '\u2026' : bodyText) },
    actions: [
      {
        type: 'button',
        text: { type: 'plain_text', text: 'Ver en Jira', emoji: true },
        action_id: `view_${r.key}`,
        url: `https://arduasolutions.atlassian.net/browse/${r.key}`
      }
    ]
  };
}
function carousel(cardRows, opts){
  return { type: 'carousel', elements: cardRows.map(r => pwiCard(r, opts)) };
}

const enCurso       = rows.filter(r => isMine(r) && inStatus(r, ['IN ANALYSIS','IN PROGRESS']));
const porEnriquecer = rows.filter(r => isMine(r) && r.status === 'To Do');
const disponibles   = rows.filter(r => !r.assigneeId && r.status === 'To Do');
const bloqueados    = rows.filter(r => isMine(r) && r.status === 'BLOCKED');

function sectionCarousel(title, rowsArr, opts, emptyTxt){
  const out = [{ type:'header', text:{ type:'plain_text', text:`${title} (${rowsArr.length})`, emoji:true } }];
  if (!rowsArr.length) { out.push(emptyNote(emptyTxt)); return out; }
  const CAP = 10;
  out.push(carousel(rowsArr.slice(0, CAP), opts));
  if (rowsArr.length > CAP) out.push(emptyNote(`_…y ${rowsArr.length - CAP} más._`));
  return out;
}

const blocks = [
  { type:'section', text:{ type:'mrkdwn', text:`:wave: *Hola, ${firstName}*\nVista de Product Manager · Todas las  Áreas` } },
  { type:'actions', elements:[
    { type:'button', style:'primary', text:{type:'plain_text',text:'+ Nuevo requerimiento',emoji:true}, url:'https://claude.ai/ask-your-org' }
  ]},
  { type:'divider' },
  ...sectionCarousel('En curso', enCurso, {}, '_Nada en curso ahora._'),
  { type:'divider' },
  ...sectionCarousel('Por enriquecer', porEnriquecer, {}, '_Nada por enriquecer._'),
  { type:'divider' },
  ...sectionCarousel('Disponibles', disponibles, {}, '_Sin requerimientos disponibles._'),
  { type:'divider' },
  ...sectionCarousel('Bloqueados', bloqueados, { useBlockedCause:true }, '_Sin bloqueos._'),
  ...buildPrioridadesGlobales(rows, { tecnico:false, counts: prioCounts, byParent }),
  { type:'context', elements:[{ type:'mrkdwn', text:`Miles · ${prioCounts.next||0} en cola · ${prioCounts.going||0} en curso · datos en vivo` }] }
];
const view={type:'home',blocks};
return [{ json:{ user_id:userId, publish_user_id:publishUserId, view:JSON.stringify(view) } }];

// Identidad
const bj = $('Build JQL').first().json;
const userId = bj.user_id;
const publishUserId = bj.publish_user_id || bj.user_id;
const firstName = bj.first_name || 'che';
const areaName = bj.area_name || 'tu área';
let _resp = $('Query Jira (via handler)').item.json;
if (typeof _resp === 'string') { try { _resp = JSON.parse(_resp); } catch(e){ _resp = {}; } }
if (_resp && _resp.body && !_resp.issues) {
  let b = _resp.body;
  if (typeof b === 'string') { try { b = JSON.parse(b); } catch(e){ b = {}; } }
  _resp = b;
}
const issues = (_resp && _resp.issues) || [];
const prioCounts = {};
let _children = $json;
if (typeof _children === 'string') { try { _children = JSON.parse(_children); } catch(e){ _children = {}; } }
if (_children && _children.body && !_children.byParent) {
  let b = _children.body; if (typeof b === 'string') { try { b = JSON.parse(b); } catch(e){ b = {}; } }
  _children = b;
}
