// --- Helpers ADF / formato ---
function adfToText(node){
  if (!node || typeof node !== 'object') return '';
  const t = node.type;
  if (t === 'text') return node.text || '';
  if (t === 'hardBreak') return ' ';
  if (t === 'mention') return (node.attrs && node.attrs.text) || '';
  if (t === 'emoji')   return (node.attrs && (node.attrs.text || node.attrs.shortName)) || '';
  if (t === 'inlineCard' || t === 'blockCard') {
    const u = node.attrs && node.attrs.url ? node.attrs.url : '';
    return u ? `[${u}]` : '[link]';
  }
  const kids = Array.isArray(node.content) ? node.content : [];
  if (t === 'tableCell' || t === 'tableHeader') return kids.map(adfToText).filter(Boolean).join(' ').trim();
  if (t === 'tableRow') return kids.map(adfToText).filter(Boolean).join(' · ');
  if (t === 'table')    return kids.map(adfToText).filter(Boolean).join('\n');
  if (t === 'paragraph') return kids.map(adfToText).join('');
  return kids.map(adfToText).filter(Boolean).join('\n');
}
function blockedCauseText(adf){
  if (!adf) return null;
  let txt = adfToText(adf).replace(/\n{2,}/g, '\n').replace(/[ \t]{2,}/g, ' ').trim();
  if (!txt) return null;
  const LIMIT = 280;
  if (txt.length > LIMIT) txt = txt.slice(0, LIMIT - 1).trimEnd() + '…';
  return txt;
}
function daysAgo(iso){ if(!iso) return null; const d=new Date(iso); if(isNaN(d)) return null; return Math.floor((Date.now()-d.getTime())/86400000); }
function agoLabel(iso){ const d=daysAgo(iso); if(d===null) return null; if(d<=0) return 'hoy'; if(d===1) return 'hace 1 día'; return `hace ${d} días`; }
function prioEmoji(p){ p=(p||'').toLowerCase(); if(p==='highest')return'🔺'; if(p==='high')return'🔴'; if(p==='medium')return'🟠'; if(p==='low')return'🟢'; return'⚪'; }
function clip(s,n){ s=String(s||''); return s.length>n ? s.slice(0,n-1).trimEnd()+'…' : s; }

// --- Prioridades globales (idéntico al resto de perfiles, INTACTO) ---
function espejoValido(issuelinks){
  if (!Array.isArray(issuelinks)) return null;
  for (const l of issuelinks) {
    const t = l.type || {};
    if (t.name === 'Problem/Incident' && t.outward === 'causes' && l.outwardIssue) {
      const k = l.outwardIssue.key || '';
      const ty = ((l.outwardIssue.fields || {}).issuetype || {}).name || '';
      if (k.startsWith('EWI-') && (ty === 'Epic' || ty === 'Story')) {
        const stObj = ((l.outwardIssue.fields || {}).status || {});
        return { key: k, type: ty, status: stObj.name || '', statusCategory: (stObj.statusCategory || {}).key || '' };
      }
    }
  }
  return null;
}
function rankCmp(a, b){ if (!a.rank && !b.rank) return 0; if (!a.rank) return 1; if (!b.rank) return -1; return a.rank < b.rank ? -1 : (a.rank > b.rank ? 1 : 0); }
const PWI_PHASE_ORDER = { 'SENT TO DEV':0, 'READY FOR DEV':1, 'IN DEVELOPMENT':2, 'BLOCKED':3 };
function phaseCmp(a, b){ const pa = PWI_PHASE_ORDER[a.status] ?? 99; const pb = PWI_PHASE_ORDER[b.status] ?? 99; if (pa !== pb) return pa - pb; return rankCmp(a, b); }
function progressBar(pct){ const filled = Math.round((pct/100)*10); return '\u2593'.repeat(filled) + '\u2591'.repeat(10-filled) + ` ${pct}%`; }
function completitud(esp, byParent){
  if (!esp) return { pct: 0, label: '\u2014' };
  const childs = (byParent && byParent[esp.key]) || [];
  if (childs.length > 0) {
    const done = childs.filter(c => c.statusCategory === 'done').length;
    const total = childs.length;
    return { pct: Math.round((done/total)*100), label: `${done}/${total}` };
  }
  const espDone = (esp.statusCategory || '').toLowerCase() === 'done';
  return { pct: espDone ? 100 : 0, label: '\u2014' };
}
function buildPrioridadesGlobales(rows, opts){
  opts = opts || {};
  const tecnico = !!opts.tecnico;
  const counts = (opts.counts && typeof opts.counts === 'object') ? opts.counts : null;
  const bp = (opts.byParent && typeof opts.byParent === 'object') ? opts.byParent : {};
  const reqs = rows.filter(r => r.issueType === 'Requirement');
  const next = [], going = [];
  for (const r of reqs) {
    const esp = espejoValido(r.issuelinks);
    r._esp = esp;
    if (!esp || esp.type === 'Epic') next.push(r); else going.push(r);
  }
  next.sort(rankCmp); going.sort(phaseCmp);
  if (counts) { counts.next = next.length; counts.going = going.length; }
  const blocks = [
    { type:'header', text:{ type:'plain_text', text:':round_pushpin: Prioridades globales', emoji:true } },
    { type:'context', elements:[{ type:'mrkdwn', text:'_Cola de Producto y Tecnología · priorización y seguimiento_' }] }
  ];
  if (next.length) {
    const h = tecnico ? ['Rank','PWI','Requerimiento','Estado','Prioridad','Área','EWI'] : ['Rank','PWI','Requerimiento','Estado','Prioridad','Área'];
    const rws = next.map((r, i) => { const base = [String(i+1), r.key, r.summary, r.status, r.priority||'—', r.area||'—']; if (tecnico) base.push(r._esp ? r._esp.key : '—'); return base; });
    blocks.push(table(`What's next? (${next.length})`, h, rws));
  } else { blocks.push(emptyNote(`*What's next? (0)* — _Sin requerimientos en cola de priorización._`)); }
  if (going.length) {
    const h = tecnico ? ['PWI','Requerimiento','Estado','Avance','Prioridad','Área','EWI'] : ['PWI','Requerimiento','Estado','Avance','Prioridad','Área'];
    const rws = going.map(r => { const e = r._esp ? r._esp.status : (r.status || '—'); const c = completitud(r._esp, bp); const av = progressBar(c.pct) + (c.label !== '—' ? ` (${c.label})` : ''); const base = [r.key, r.summary, e, av, r.priority||'—', r.area||'—']; if (tecnico) base.push(r._esp ? r._esp.key : '—'); return base; });
    blocks.push(table(`What's going on? (${going.length})`, h, rws));
  } else { blocks.push(emptyNote(`*What's going on? (0)* — _Nada en desarrollo ahora._`)); }
  return blocks;
}

function row(it){
  const f = it.fields || {};
  const a = f.assignee || null;
  return {
    key: it.key, summary: f.summary || '',
    status: f.status ? f.status.name : '',
    assignee: a ? (a.displayName || '') : '',
    assigneeId: a ? (a.accountId || '') : '',
    area: f.customfield_10310 ? (f.customfield_10310.value || f.customfield_10310.name || '') : '',
    priority: f.priority ? f.priority.name : '',
    blockedCause: blockedCauseText(f.customfield_10306),
    blockedSince: f.statuscategorychangedate || null,
    issueType: f.issuetype ? f.issuetype.name : '',
    isSubtask: !!(f.issuetype && f.issuetype.subtask),
    project: (it.fields && it.fields.project && it.fields.project.key) || (String(it.key||'').split('-')[0]),
    issuelinks: (it.fields && it.fields.issuelinks) || [],
    rank: f.customfield_10019 || ''
  };
}
const rows = issues.map(row);
const ewiRows = rows.filter(r => r.project === 'EWI' && !r.isSubtask);
const pwiRows = rows.filter(r => r.project === 'PWI');
function inStatus(r, arr){ const s=(r.status||'').toUpperCase(); return arr.some(x => String(x).toUpperCase() === s); }

function table(caption, header, dataRows){
  const head = header.map(h => ({type:'raw_text', text:h}));
  const body = dataRows.map(cells => cells.map(c => ({type:'raw_text', text:String(c)})));
  return { type:'data_table', caption, rows:[head, ...body] };
}
function emptyNote(txt){ return { type:'context', elements:[{type:'mrkdwn', text:txt}] }; }

function pwiCard(r, opts){
  opts = opts || {};
  const ago = agoLabel(r.blockedSince);
  const subParts = [];
  if (r.priority) subParts.push(`${prioEmoji(r.priority)} ${r.priority}`);
  if (r.area)     subParts.push(`📍 ${r.area}`);
  if (ago)        subParts.push(`⏱ ${ago}`);
  let bodyText = opts.useBlockedCause ? (r.blockedCause ? r.blockedCause : '_Sin motivo en Blocked cause_') : (r.summary || '_Sin descripción_');
  let _bodyClipped = (bodyText && bodyText.length > 200 ? bodyText.slice(0, 199).trimEnd() + '\u2026' : bodyText);
  try {
    const _ch = (typeof byParent !== 'undefined' && byParent) ? (byParent[r.key] || []) : [];
    if (_ch.length > 0) {
      const _done = _ch.filter(c => c.statusCategory === 'done').length;
      _bodyClipped = `${_bodyClipped}\n\n_\`${_done}/${_ch.length}\` Tareas completadas_`;
    }
  } catch (e) {}
  const card = {
    type: 'card', block_id: `card-${r.key}`,
    slack_icon: { type: 'icon', name: 'rocket' },
    title:    { type: 'mrkdwn', text: `*${r.key}* · ${clip(r.summary, 80)}` },
    subtitle: { type: 'mrkdwn', text: subParts.join('  ·  ') || '—' },
    body:     { type: 'mrkdwn', text: _bodyClipped }
  };
  if (opts.withButton) {
    card.actions = [{ type:'button', text:{ type:'plain_text', text:'Ver en Jira', emoji:true }, action_id:`view_${r.key}`, url:`https://arduasolutions.atlassian.net/browse/${r.key}` }];
    if (opts.selfAssign) {
      if (takingKey && r.key === takingKey) {
        card.actions.push({ type:'button', text:{ type:'plain_text', text:'⏳ Tomando…', emoji:true }, action_id:`taking_${r.key}`, value:r.key });
      } else if (isTL) {
        card.actions.push({ type:'button', style:'primary', text:{ type:'plain_text', text:'Asignar', emoji:true }, action_id:`open_assign_${r.key}`, value:r.key });
      } else {
        card.actions.push({ type:'button', style:'primary', text:{ type:'plain_text', text:'Tomar', emoji:true }, action_id:`self_assign_${r.key}`, value:r.key });
      }
    }
  }
  return card;
}
function carousel(cardRows, opts){ return { type:'carousel', elements: cardRows.map(r => pwiCard(r, opts)) }; }
function sectionCarousel(title, rowsArr, opts, emptyTxt){
  opts = opts || {};
  const out = [{ type:'header', text:{ type:'plain_text', text:`${title} (${rowsArr.length})`, emoji:true } }];
  if (opts.legend) out.push({ type:'context', elements:[{ type:'mrkdwn', text: opts.legend }] });
  if (!rowsArr.length) { out.push(emptyNote(emptyTxt)); return out; }
  const CAP = 10;
  out.push(carousel(rowsArr.slice(0, CAP), opts));
  if (rowsArr.length > CAP) out.push(emptyNote(`_…y ${rowsArr.length - CAP} más._`));
  return out;
}

// === CAPACITY (solo liderazgo técnico) ===
function buildCapacity(ewiR, roster){
  // 🧪 ICONOS POR CARGA — slack_icon exige un `name` de un set cerrado.
  // Un name INVALIDO hace que Slack rechace el views.publish ENTERO (ver H5).
  // 'rocket' esta validado. Los otros son CANDIDATOS — probar uno por uno y
  // si Slack rechaza, cambiar el name aca (queda aislado en este mapa).
  // NOTA: slack_icon.name solo acepta un enum CERRADO de Slack. white_check_mark,
  // hourglass y warning fueron RECHAZADOS (rompen el views.publish entero, error
  // 'must be a valid enum value'). 'rocket' es el unico validado. La señal de carga
  // va en el emoji del subtitle (⚪🟢🟠🔴), no en el icono del card.
  const CARGA_ICON = { sin:'rocket', margen:'rocket', ok:'rocket', alta:'rocket' };
  function loadLabel(n){
    if (n === 0) return { txt:'sin carga',  emoji:'⚪', icon: CARGA_ICON.sin };
    if (n <= 2)  return { txt:'con margen', emoji:'🟢', icon: CARGA_ICON.margen };
    if (n <= 4)  return { txt:'ok',         emoji:'🟠', icon: CARGA_ICON.ok };
    return { txt:'carga alta', emoji:'🔴', icon: CARGA_ICON.alta };
  }
  const byDev = {};
  for (const r of ewiR) { const id = r.assigneeId || ''; if (!id) continue; (byDev[id] = byDev[id] || []).push(r); }
  const devs = (roster || []).map(p => {
    const mine = byDev[p.jiraId] || [];
    const enCurso    = mine.filter(r => inStatus(r, ['IN PROGRESS','CODE REVIEW'])).length;
    const bloqueados = mine.filter(r => (r.status||'').toUpperCase() === 'BLOCKED').length;
    const sinEmpezar = mine.filter(r => (r.status||'').toUpperCase() === 'READY FOR DEV').length;
    const refinam    = mine.filter(r => inStatus(r, ['TO REFINEMENT','IN REFINEMENT'])).length;
    const total = enCurso + bloqueados + sinEmpezar + refinam;
    return { name:p.name, role:p.role, jiraId:p.jiraId, enCurso, bloqueados, sinEmpezar, refinam, total, keys: mine.map(r => r.key) };
  });
  devs.sort((a,b) => b.total - a.total);
  const out = [
    { type:'header', text:{ type:'plain_text', text:':busts_in_silhouette: Capacity del equipo', emoji:true } },
    { type:'context', elements:[{ type:'mrkdwn', text:'_Carga por persona · tickets activos de Tecnología_' }] }
  ];
  if (!devs.length) { out.push(emptyNote('_No hay personas de Tecnología en el padrón._')); return out; }
  // Cards de dev como CAROUSEL (navegable horizontal). Cap 10 como las demás secciones.
  const CAP = 10;
  const cap_cards = devs.slice(0, CAP).map(d => {
    const load = loadLabel(d.total);
    const counts = [`▶️ ${d.enCurso} en curso`, `⛔ ${d.bloqueados} bloq.`, `📋 ${d.sinEmpezar} sin empezar`, `🔍 ${d.refinam} refinam.`].join('   ·   ');
    let body = d.keys.length ? `${counts}\n\n_${d.keys.slice(0,8).join(' · ')}${d.keys.length>8?` …(+${d.keys.length-8})`:''}_` : `${counts}\n\n_Sin tickets activos._`;
    return {
      type:'card', block_id:`cap-${(d.name||'').replace(/[^A-Za-z0-9]/g,'_').slice(0,40)}`,
      slack_icon:{ type:'icon', name: load.icon },
      title:{ type:'mrkdwn', text:`*${clip(d.name||'Sin nombre',60)}*` },
      subtitle:{ type:'mrkdwn', text:`${load.emoji} ${load.txt}${d.role ? '  ·  '+clip(d.role,30) : ''}` },
      body:{ type:'mrkdwn', text:body },
      actions: d.jiraId ? [{
        type:'button',
        text:{ type:'plain_text', text:'Ver en Jira', emoji:true },
        action_id:`cap_jira_${(d.name||'').replace(/[^A-Za-z0-9]/g,'_').slice(0,30)}`,
        url:`https://arduasolutions.atlassian.net/jira/software/c/projects/EWI/boards/174?assignee=${encodeURIComponent(d.jiraId)}`
      }] : []
    };
  });
  out.push({ type:'carousel', elements: cap_cards });
  if (devs.length > CAP) out.push(emptyNote(`_…y ${devs.length - CAP} personas más._`));
  return out;
}

// === Reparto por estado (dev común) ===
const devEnCurso     = ewiRows.filter(r => inStatus(r, ['IN PROGRESS','CODE REVIEW']) && r.assignee);
const devDisponibles = ewiRows.filter(r => (r.status||'').toUpperCase() === 'READY FOR DEV' && !r.assignee);
