blocks.push(...sectionCarousel('Sin asignar · Listos para tomar', devDisponibles, { ...OPT, selfAssign:true, legend:'💡 Tickets listos para desarrollar. Tomá el que vayas a trabajar para asignártelo.' }, '_Sin tickets disponibles._'));

