let areaName = null;
if (areaId) {
  const areas = $('Resolve Area Name').first().json.results || [];
  const match = areas.find(a => a.id === areaId);
  areaName = match ? (match.properties?.Name?.title?.[0]?.plain_text || null) : null;
}

function esc(s){ return String(s).replace(/"/g, '\\"'); }

let jql = '';
if (profile === 'externo') {
  // Externo: solo necesita los PWI Requirement activos (Prioridades globales).
  jql = `project = PWI AND issuetype = Requirement AND status NOT IN (Done, DEPRECATED) ORDER BY status ASC`;
} else if (profile === 'stakeholder' || profile === 'lider') {
  jql = `project = PWI AND status NOT IN (Done, DEPRECATED) ORDER BY status ASC`;
} else if (profile === 'producto') {
  jql = `project = PWI AND status NOT IN (Done, DEPRECATED) ORDER BY status ASC`;
} else if (profile === 'it_lead' || profile === 'tech_lead') {
  // Liderazgo tecnico (CTO/Head o TL): EWI activo de TODO el equipo (Capacity
  // necesita ver a todos) + PWI Requirement activos (Prioridades globales).
  jql = `( project = EWI AND status NOT IN (Done, DEPRECATED) ) OR ( project = PWI AND issuetype = Requirement AND status NOT IN (Done, DEPRECATED) ) ORDER BY status ASC`;
} else if (profile === 'tecnico') {
  // Dev comun: lo mio (in progress/code review/blocked propios) + disponibles
  // (ready for dev sin asignar). Sin refinamiento. + PWI Requirement (Prioridades).
  const mine = jiraId ? `assignee = "${esc(jiraId)}"` : 'assignee IS EMPTY';
  const devStates = '"IN PROGRESS","CODE REVIEW",BLOCKED,"READY FOR DEV"';
  const ewiJql = `project = EWI AND ( (${mine} AND status IN (${devStates})) OR (assignee IS EMPTY AND status IN ("READY FOR DEV")) )`;
  jql = `( ${ewiJql} ) OR ( project = PWI AND issuetype = Requirement AND status NOT IN (Done, DEPRECATED) ) ORDER BY status ASC`;
} else {
  jql = `project = PWI AND assignee IS EMPTY AND status = "To Do"`;
}

return [{ json: { jql, profile, jira_id: jiraId, area_name: areaName, is_tech_lead: isTL,
                  user_id: rp.user_id, publish_user_id: rp.publish_user_id, first_name: rp.first_name,
                  taking: ($('Classify Event').first().json.taking || ''),
                  tab: ($('Classify Event').first().json.tab || '') } }];

// ============================================================================
// miles-slack-event-router · Resolve Children Keys
// ----------------------------------------------------------------------------
// Entre Query Jira y Fetch Children Progress. Resuelve los EWI espejo (Story) de
// las PWI que caen en "What's going on" y arma parentKeys para pedir sus child
// al handler (operación search_children). Preserva los issues originales.
// ============================================================================
let _resp = $json;
if (typeof _resp === 'string') { try { _resp = JSON.parse(_resp); } catch(e){ _resp = {}; } }
if (_resp && _resp.body && !_resp.issues) {
  let b = _resp.body;
  if (typeof b === 'string') { try { b = JSON.parse(b); } catch(e){ b = {}; } }
  _resp = b;
}
const issues = (_resp && _resp.issues) || [];

function espejoStory(issuelinks){
  if (!Array.isArray(issuelinks)) return null;
  for (const l of issuelinks) {
    const t = l.type || {};
    if (t.name === 'Problem/Incident' && t.outward === 'causes' && l.outwardIssue) {
      const k = l.outwardIssue.key || '';
      const ty = ((l.outwardIssue.fields || {}).issuetype || {}).name || '';
      if (k.startsWith('EWI-') && ty === 'Story') return k;
    }
  }
  return null;
}

const parentKeys = [];
function pushKey(k){ if (k && !parentKeys.includes(k)) parentKeys.push(k); }
for (const it of issues) {
  const f = it.fields || {};
  const proj = (f.project && f.project.key) || String(it.key||'').split('-')[0];
  if (proj === 'PWI' && f.issuetype && f.issuetype.name === 'Requirement') {
    pushKey(espejoStory(f.issuelinks));
  }
  if (proj === 'EWI' && f.issuetype && f.issuetype.name === 'Story') {
    pushKey(it.key);
  }
}

return [{ json: { _issuesPassthrough: _resp, parentKeys } }];

// ============================================================================
// miles-slack-event-router · Merge Roster
// ----------------------------------------------------------------------------
// Entre 'Query Tech Roster' (HTTP Notion) y 'Switch — Profile'.
// Recompone el $json que esperan los builders SIN perder byParent:
//   - byParent      : se relee por referencia de 'Fetch Children Progress'
//   - approval_cards: idem (lo arrastra la rama lider, no pasa por aca, pero
//                     lo preservamos por compatibilidad si estuviera presente)
//   - techRoster    : padron de Tecnologia (solo lo usan los builders tecnicos)
//
// El padron sale de 'Query Tech Roster' = Notion Stakeholders filtrado por
// Business Area = Technology. Por cada persona: name, jiraId, slackId.
// Los builders no-tecnicos ignoran techRoster; siguen leyendo byParent de $json.
// ============================================================================

// byParent (de Fetch Children Progress, por referencia)
let prev = {};
try { prev = $('Fetch Children Progress').item.json; } catch (e) { prev = {}; }
if (typeof prev === 'string') { try { prev = JSON.parse(prev); } catch(e){ prev = {}; } }
if (prev && prev.body && !prev.byParent) {
  let b = prev.body; if (typeof b === 'string') { try { b = JSON.parse(b); } catch(e){ b = {}; } }
  prev = b;
}
const byParent = (prev && prev.byParent) || {};

// Padron de Tecnologia (respuesta de Query Tech Roster en $json)
let rosterRes = $json;
if (typeof rosterRes === 'string') { try { rosterRes = JSON.parse(rosterRes); } catch(e){ rosterRes = {}; } }
if (rosterRes && rosterRes.body && !rosterRes.results) {
  let b = rosterRes.body; if (typeof b === 'string') { try { b = JSON.parse(b); } catch(e){ b = {}; } }
  rosterRes = b;
}
const results = (rosterRes && rosterRes.results) || [];

const techRoster = [];
// Excluir liderazgo del analisis de carga: Capacity es de EJECUTORES.
// Cualquier persona con Group Head o C-Level (CTO, Head of Technology) queda fuera.
const LEADERSHIP_GROUPS = ['Head', 'C-Level'];
for (const page of results) {
  try {
    const pr = page.properties || {};
    const name   = pr['Name']?.title?.[0]?.plain_text || '';
    const jiraId = pr['Jira ID']?.rich_text?.[0]?.plain_text || '';
    const slackId= pr['Slack ID']?.rich_text?.[0]?.plain_text || '';
    const role   = pr['Role']?.rich_text?.[0]?.plain_text || '';
    const groups = (pr['Group']?.multi_select || []).map(g => g.name);
    const isLeadership = groups.some(g => LEADERSHIP_GROUPS.includes(g));
    if (name && !isLeadership) techRoster.push({ name, jiraId, slackId, role });
  } catch (e) {}
}

return [{ json: { byParent, techRoster } }];

// ============================================================================
// miles-slack-event-router · Split Locks
// ----------------------------------------------------------------------------
// Desagrega los locks Pending del lider (de 'Query Approval Locks') a N items,
// uno por lock, para que 'Fetch Thread' (HTTP) lea cada hilo por item.
// NO hace llamadas externas. Arrastra byParent (de Fetch Children Progress)
// en cada item para reensamblar luego.
// Sin pendientes -> 1 item { approval_empty:true, byParent }.
// ============================================================================

let prev = $('Fetch Children Progress').item.json;
if (typeof prev === 'string') { try { prev = JSON.parse(prev); } catch(e){ prev = {}; } }
if (prev && prev.body && !prev.byParent) {
  let b = prev.body; if (typeof b === 'string') { try { b = JSON.parse(b); } catch(e){ b = {}; } }
  prev = b;
}
const byParent = (prev && prev.byParent) || {};

const locks = ($('Query Approval Locks').item.json.results) || [];

function daysAgo(iso){ if(!iso) return null; const d=new Date(iso); if(isNaN(d)) return null; return Math.floor((Date.now()-d.getTime())/86400000); }

const rows = [];
for (const lock of locks){
  const p = lock.properties || {};
  const threadId    = p['Thread ID']?.title?.[0]?.plain_text || '';
  const channelId   = p['Channel ID']?.rich_text?.[0]?.plain_text || '';
  const requesterId = p['Requester ID']?.rich_text?.[0]?.plain_text || '';
  const lockedAt    = p['Locked At']?.created_time || lock.created_time || '';
  if (!threadId || !channelId) continue;
  const threadUrl = 'https://arduasolutions.slack.com/archives/' + channelId + '/p' + threadId.replace('.', '')
    + '?thread_ts=' + threadId + '&cid=' + channelId;
  rows.push({ threadId, channelId, requesterId, lockedAt, threadUrl, daysWaiting: daysAgo(lockedAt), byParent });
}

if (rows.length === 0) return [{ json: { approval_empty: true, byParent } }];
return rows.map(r => ({ json: r }));

// ============================================================================
// miles-slack-event-router · Parse Thread
// ----------------------------------------------------------------------------
// Por item: toma la respuesta de 'Fetch Thread' (Slack conversations.replies)
// en $json y los datos de la card por referencia a 'Split Locks'. Extrae el
// Problema (texto del hilo) y arma fullText (material para Groq). Re-valida que
// el hilo no este ya resuelto en Slack -> si lo esta, marca _skip=true.
// El item vacio (approval_empty) pasa de largo.
// ============================================================================

const me = $json;
let src;
try { src = $('Split Locks').item.json; }
catch (e) { src = {}; }

if (src && src.approval_empty) {
  return [{ json: { approval_empty: true, byParent: src.byParent || {} } }];
}

const replies = (me && me.messages) || [];

function blocksToText(blocks){
  if (!Array.isArray(blocks)) return '';
  const parts = [];
  function walk(el){
    if (!el || typeof el !== 'object') return;
    const t = el.type;
    if (t === 'text')      parts.push(el.text || '');
    else if (t === 'emoji') parts.push(':' + (el.name || '') + ':');
    else if (t === 'link')  parts.push(el.text || el.url || '');
    else if (t === 'user')  parts.push('<@' + (el.user_id || '') + '>');
    const kids = el.elements || el.element || null;
    if (Array.isArray(kids)) kids.forEach(walk);
  }
  for (const b of blocks){ if (b && Array.isArray(b.elements)) b.elements.forEach(walk); parts.push('\n'); }
  return parts.join('');
}
function extractFromText(text){
  if (!text) return '';
  const startRe = /:mag:\s*_?\s*Problema\s*_?/i;
  const m = text.match(startRe);
  if (!m) return '';
  let rest = text.slice(m.index + m[0].length);
  const cuts = [':compass:', ':warning:', ':white_check_mark:', ':rotating_light:', ':bust_in_silhouette:', '*Enviado', 'Enviado mediante'];
  let cut = rest.length;
  for (const c of cuts){ const i = rest.indexOf(c); if (i !== -1 && i < cut) cut = i; }
  return rest.slice(0, cut).replace(/^[\s_*:]+/, '').replace(/[\s_*]+$/, '').trim();
}
function rootText(msg){
  if (!msg) return '';
  const t = (msg.text || '').trim();
  if (t) return t;
  return blocksToText(msg.blocks).trim();
}
function isResolved(messages){
  for (const m of messages){
    const t = m.text || '';
    if (t.indexOf('\u{1F389} Requerimiento creado') !== -1) return true;
    if (/tu requerimiento fue rechazado por/i.test(t)) return true;
  }
  return false;
}

const root = replies[0] || null;
const full = rootText(root);
let problema = extractFromText(full);
if (!problema) problema = extractFromText(blocksToText(root && root.blocks));

const skip = replies.length > 0 && isResolved(replies);

return [{ json: {
  threadId: src.threadId, channelId: src.channelId, requesterId: src.requesterId,
  lockedAt: src.lockedAt, threadUrl: src.threadUrl, daysWaiting: src.daysWaiting,
  byParent: src.byParent || {},
  fullText: full,
  problemaParser: problema,
  _skip: skip
} }];

